  "inlineSchema": "// ==========================================\n// 4. АВТОРИЗАЦИЯ И ДОСТУПЫ (RBAC - Role Based Access Control)\n// ==========================================\n// Масштабируемая система прав (можно сделать админов, модераторов, VIP и т.д.)\nmodel Role {\n  id          String  @id @default(uuid())\n  name        String  @unique // 'SUPER_ADMIN', 'USER', 'MANAGER'\n  description String?\n\n  users       UserRole[]\n  permissions RolePermission[] // Права, привязанные к роли\n\n  @@schema(\"acls_db\")\n}\n\n// Связующая таблица Многие-ко-Многим (Пользователь <-> Роль)\nmodel UserRole {\n  userId String\n  roleId String\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  role Role @relation(fields: [roleId], references: [id], onDelete: Cascade)\n\n  @@id([userId, roleId]) // Композитный первичный ключ\n  @@schema(\"acls_db\")\n}\n\n// Конкретные действия (например: 'DELETE_USERS', 'EDIT_POSTS')\nmodel Permission {\n  id          String  @id @default(uuid())\n  action      String  @unique // Название права\n  description String?\n\n  roles RolePermission[]\n\n  @@schema(\"acls_db\")\n}\n\n// Связующая таблица Многие-ко-Многим (Роль <-> Право)\nmodel RolePermission {\n  roleId       String\n  permissionId String\n\n  role       Role       @relation(fields: [roleId], references: [id], onDelete: Cascade)\n  permission Permission @relation(fields: [permissionId], references: [id], onDelete: Cascade)\n\n  @@id([roleId, permissionId])\n  @@schema(\"acls_db\")\n}\n\n// Абстрагируем провайдеров. Теперь Firebase — лишь один из вариантов.\nmodel Account {\n  id     String @id @default(uuid())\n  userId String\n\n  // 'firebase', 'google', 'credentials', 'apple', 'github'\n  provider String\n\n  // Уникальный ID со стороны провайдера (твой бывший firebaseUid)\n  providerAccountId String\n\n  // Опциональные поля для OAuth или локальных паролей\n  passwordHash String? // Если решишь добавить вход по паролю\n  refreshToken String? // Для OAuth\n  accessToken  String? // Для OAuth\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Один провайдер не может иметь два одинаковых аккаунта\n  @@unique([provider, providerAccountId])\n  @@schema(\"auths_db\")\n}\n\n// ==========================================\n// 3. УПРАВЛЕНИЕ СЕССИЯМИ (Security & Scaling)\n// ==========================================\n// Позволяет смотреть \"Активные устройства\" и принудительно разлогинивать\nmodel Session {\n  id           String   @id @default(uuid())\n  userId       String\n  sessionToken String   @unique // Токен сессии (JWT или opaque token)\n  expiresAt    DateTime // Когда сессия протухает\n\n  // Метаданные для безопасности\n  ipAddress String?\n  userAgent String? // Браузер/телефон\n\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@schema(\"auths_db\")\n}\n\n// fs\nenum FsNodeType {\n  None\n  FileJson // Stores structured text/data in content_json\n  FileStorageUrl // Stores an S3/Cloud URL in the content_url column content_json {url:string}\n  FileBinary // Stores raw file data in content_binary\n  Directory // Acts as a folder (uses the parent/child relations)\n\n  @@map(\"fs_node_type\")\n  @@schema(\"fss_db\")\n}\n\nmodel FsNode {\n  id             String     @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  name           String     @db.String(255)\n  type           FsNodeType\n  content_json   Json?\n  content_binary Bytes?\n\n  // Настройка рекурсивной связи (Self-relation)\n  parentId  String?  @map(\"parent_id\") @db.Uuid\n  ancestors String[] @db.Uuid\n\n  parent   FsNode?  @relation(\"FileToFile\", fields: [parentId], references: [id])\n  children FsNode[] @relation(\"FileToFile\")\n\n  @@unique([name, parentId], name: \"unique_name_in_folder\")\n  // Создаем инвертированный (GIN) индекс для массива ancestors\n  @@index([ancestors], type: Gin, name: \"idx_ancestors\")\n  @@map(\"fs_node\")\n  @@schema(\"fss_db\")\n}\n\nmodel Indentity {\n  userId String\n  email  String  @unique\n  name   String?\n  avatar String?\n\n  // Статусы аккаунта (для банов, верификации)\n  isActive   Boolean @default(true)\n  isVerified Boolean @default(false)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  users User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@schema(\"ids_db\")\n}\n\ngenerator client {\n  provider        = \"prisma-client\"\n  output          = \"./generated\"\n  previewFeatures = [\"multiSchema\"]\n}\n\ndatasource db {\n  provider = \"cockroachdb\"\n  schemas  = [\"public\", \"users_db\", \"fss_db\", \"auths_db\", \"acls_db\", \"ids_db\"]\n}\n\nenum crdb_internal_region {\n  gcp_us_central1 @map(\"gcp-us-central1\")\n\n  @@schema(\"public\")\n}\n\nmodel User {\n  id       String      @id @default(uuid())\n  // Связи\n  ids      Indentity[] // Способы входа (Firebase, Google, etc.)\n  accounts Account[] // Способы входа (Firebase, Google, etc.)\n  sessions Session[] // Активные сессии (устройства)\n  roles    UserRole[] // Роли пользователя (RBAC)\n\n  @@schema(\"users_db\")\n}\n",
